Greedy best-insertion: for each order evaluate top 3 nearest non-empty vehicles, pick the assignment with minimum marginal cost increase; if none is feasible, fall back to sequential insertion into any existing or a new vehicle.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const topK = 3

	for jj := range oris {
		// Collect active vehicle candidates
		type candDist struct {
			idx  int
			dist float64
		}
		var cdlist []candDist
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			if dispatch.Assigns[ii].StationsLen > 0 {
				d := cal_dis(dispatch.Assigns[ii].StationCurrent, oris[jj])
				cdlist = append(cdlist, candDist{ii, d})
			}
		}
		// Sort by distance ascending, keep topK
		if len(cdlist) > 1 {
			for i := 0; i < len(cdlist)-1; i++ {
				for j := i + 1; j < len(cdlist); j++ {
					if cdlist[j].dist < cdlist[i].dist {
						cdlist[i], cdlist[j] = cdlist[j], cdlist[i]
					}
				}
			}
		}
		if len(cdlist) > topK {
			cdlist = cdlist[:topK]
		}

		bestIdx := -1
		bestScore := 1e18

		// Evaluate each top candidate
		for _, cd := range cdlist {
			ii := cd.idx
			oldCost := dispatch.Assigns[ii].Cost
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost >= 0 {
				score := (newCost - oldCost) + 0.01*cd.dist
				if score < bestScore {
					bestScore = score
					bestIdx = ii
				}
			}
			// Rollback tentative insertion
			dispatch.Assigns[ii].RemoveShip(total_ship + jj)
			dispatch.Assigns[ii].GenRoute()
		}

		inserted := false
		// Commit best candidate
		if bestIdx >= 0 {
			if dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[bestIdx].GenRoute()
				if dispatch.Assigns[bestIdx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[bestIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[bestIdx].GenRoute()
				}
			}
		}

		// Fallback: safe seed sequential insertion into any existing vehicle
		if !inserted {
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						inserted = true
						break
					}
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}

		// Last resort: open a new vehicle
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			ii := dispatch.AssignsLen
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					dispatch.AssignsLen = ii + 1
					inserted = true
				} else {
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}

		// Order must be processed; if still not inserted it's logically impossible
		_ = inserted
	}

	dispatch.RenewnTotalCost()
	return dispatch

